import { createContext, useContext, useEffect, useState, useCallback } from 'react'
import type { ReactNode } from 'react'
import type { AuthUser, AuthSession } from '@supabase/supabase-js'
import { supabase } from '../config/supabase.ts'

// Types pour les données chargées depuis la base
interface Profile {
  id: string
  full_name: string | null
  avatar_url: string | null
  created_at: string
}

interface Subscription {
  id: string
  user_id: string
  plan: string
  status: string
  current_period_end: string | null
}

interface AuthContextValue {
  user: AuthUser | null
  session: AuthSession | null
  profile: Profile | null
  subscription: Subscription | null
  isLoading: boolean
  isAuthenticated: boolean
  signInWithEmail: (email: string, password: string) => Promise<{ error: string | null }>
  signUpWithEmail: (email: string, password: string, fullName: string) => Promise<{ error: string | null }>
  signOut: () => Promise<void>
}

const AuthContext = createContext<AuthContextValue | null>(null)

async function fetchProfile(userId: string): Promise<Profile | null> {
  const { data, error } = await supabase
    .from('profiles')
    .select('*')
    .eq('id', userId)
    .single()

  if (error) {
    console.error('Erreur chargement profil:', error.message)
    return null
  }
  return data as Profile
}

async function fetchSubscription(userId: string): Promise<Subscription | null> {
  const { data, error } = await supabase
    .from('subscriptions')
    .select('*')
    .eq('user_id', userId)
    .single()

  if (error) {
    // Pas d'abonnement n'est pas une erreur critique
    if (error.code !== 'PGRST116') {
      console.error('Erreur chargement abonnement:', error.message)
    }
    return null
  }
  return data as Subscription
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null)
  const [session, setSession] = useState<AuthSession | null>(null)
  const [profile, setProfile] = useState<Profile | null>(null)
  const [subscription, setSubscription] = useState<Subscription | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  // Charge profil et abonnement pour un utilisateur
  const loadUserData = useCallback(async (userId: string) => {
    const [profileData, subscriptionData] = await Promise.all([
      fetchProfile(userId),
      fetchSubscription(userId),
    ])
    setProfile(profileData)
    setSubscription(subscriptionData)
  }, [])

  // Nettoie les données utilisateur
  const clearUserData = useCallback(() => {
    setUser(null)
    setSession(null)
    setProfile(null)
    setSubscription(null)
  }, [])

  useEffect(() => {
    // Récupère la session initiale
    supabase.auth.getSession().then(({ data: { session: currentSession } }) => {
      setSession(currentSession)
      setUser(currentSession?.user ?? null)
      if (currentSession?.user) {
        loadUserData(currentSession.user.id).then(() => setIsLoading(false))
      } else {
        setIsLoading(false)
      }
    })

    // Écoute les changements d'état d'authentification
    const { data: { subscription: authSubscription } } = supabase.auth.onAuthStateChange(
      (event, newSession) => {
        setSession(newSession)
        setUser(newSession?.user ?? null)

        if (event === 'SIGNED_IN' && newSession?.user) {
          loadUserData(newSession.user.id)
        }

        if (event === 'SIGNED_OUT') {
          clearUserData()
        }
      }
    )

    return () => {
      authSubscription.unsubscribe()
    }
  }, [loadUserData, clearUserData])

  const signInWithEmail = useCallback(async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) {
      return { error: error.message }
    }
    return { error: null }
  }, [])

  const signUpWithEmail = useCallback(async (email: string, password: string, fullName: string) => {
    const { error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: { full_name: fullName },
      },
    })
    if (error) {
      return { error: error.message }
    }
    return { error: null }
  }, [])

  const handleSignOut = useCallback(async () => {
    await supabase.auth.signOut()
  }, [])

  const value: AuthContextValue = {
    user,
    session,
    profile,
    subscription,
    isLoading,
    isAuthenticated: !!user,
    signInWithEmail,
    signUpWithEmail,
    signOut: handleSignOut,
  }

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
}

export function useAuth(): AuthContextValue {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth doit être utilisé dans un AuthProvider')
  }
  return context
}

